import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreSurroundingSpaces());

        CSVFormat newFormat = format.withIgnoreSurroundingSpaces();

        assertNotNull(newFormat);
        assertTrue(newFormat.getIgnoreSurroundingSpaces());

        // Ensure original object unchanged (immutability)
        assertFalse(format.getIgnoreSurroundingSpaces());

        // Check chaining returns new instance with correct flag
        CSVFormat chained = newFormat.withIgnoreSurroundingSpaces();
        assertTrue(chained.getIgnoreSurroundingSpaces());
    }
}
